static Instruction *foldSelectFabsWithFcmpZero(FCmpInst &I,
                                                InstCombinerImpl &IC) {
  Value *X;
  CmpInst::Predicate SelectPred;
  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);

  if (!match(Op1, m_AnyZeroFP()))
    return nullptr;

  // Match the fabs-like select pattern:
  //   select (fcmp oge X, 0.0), X, (fneg X)
  // or the swapped form:
  //   select (fcmp olt X, 0.0), (fneg X), X
  // Also match equality-based patterns and arbitrary conditions:
  //   select cond, X, (fneg X)
  //   select cond, (fneg X), X
  bool IsFabsSelect = match(
      Op0, m_OneUse(m_Select(m_FCmp(SelectPred, m_Value(X), m_AnyZeroFP()),
                             m_Deferred(X), m_FNeg(m_Deferred(X)))));
  if (!IsFabsSelect) {
    // Try swapped form with fcmp condition:
    // select (fcmp pred X, 0.0), (fneg X), X
    IsFabsSelect = match(
        Op0, m_OneUse(m_Select(m_FCmp(SelectPred, m_Value(X), m_AnyZeroFP()),
                               m_FNeg(m_Deferred(X)), m_Deferred(X))));
  }
  if (!IsFabsSelect) {
    // Try arbitrary condition: select cond, X, (fneg X)
    SelectPred = CmpInst::BAD_FCMP_PREDICATE;
    IsFabsSelect = match(
        Op0, m_OneUse(m_Select(m_Value(), m_Value(X), m_FNeg(m_Deferred(X)))));
    if (!IsFabsSelect) {
      // Try swapped arbitrary: select cond, (fneg X), X
      IsFabsSelect = match(
          Op0, m_OneUse(m_Select(m_Value(), m_FNeg(m_Value(X)), m_Deferred(X))));
      if (!IsFabsSelect)
        return nullptr;
    }
  }

  // For the fcmp-based select, check that the condition is a valid
  // fabs-like comparison (OGE/OGT/UGE/UGT) or an equality check
  // (OEQ/UEQ/ONE/UNE). For arbitrary conditions, any condition works
  // because the select result is 0 iff X is 0 regardless of which
  // branch is taken.
  if (SelectPred != CmpInst::BAD_FCMP_PREDICATE) {
    bool IsGE = SelectPred == FCmpInst::FCMP_OGE ||
                SelectPred == FCmpInst::FCMP_UGE;
    bool IsGT = SelectPred == FCmpInst::FCMP_OGT ||
                SelectPred == FCmpInst::FCMP_UGT;
    bool IsEq = SelectPred == FCmpInst::FCMP_OEQ ||
                SelectPred == FCmpInst::FCMP_UEQ ||
                SelectPred == FCmpInst::FCMP_ONE ||
                SelectPred == FCmpInst::FCMP_UNE;
    if (!IsGE && !IsGT && !IsEq)
      return nullptr;
  }

  // For the select-based fabs, we can only safely fold for predicates where
  // the sign of zero doesn't matter: equality/inequality and nan checks.
  switch (I.getPredicate()) {
  case FCmpInst::FCMP_OEQ:
  case FCmpInst::FCMP_UEQ:
  case FCmpInst::FCMP_ONE:
  case FCmpInst::FCMP_UNE:
  case FCmpInst::FCMP_ORD:
  case FCmpInst::FCMP_UNO:
    // fabs(X) == 0.0  --> X == 0.0
    // fabs(X) != 0.0  --> X != 0.0
    // isnan(fabs(X))  --> isnan(X)
    // !isnan(fabs(X)) --> !isnan(X)
    return new FCmpInst(I.getPredicate(), X, Op1, "", &I);
  default:
    return nullptr;
  }
}
